import Database from "better-sqlite3";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

export interface CommentRow {
  id: number;
  parent_id: number | null;
  author: string;
  body: string;
  created_at: string;
}

export interface CommentNode {
  id: number;
  parentId: number | null;
  author: string;
  body: string;
  createdAt: string;
  children: CommentNode[];
}

const here = dirname(fileURLToPath(import.meta.url));
// Project root: src/lib -> src -> project root
const projectRoot = resolve(here, "..", "..");
const dbPath = process.env.COMMENTS_DB_PATH ?? resolve(projectRoot, "comments.db");

let dbInstance: Database.Database | null = null;

function getDb(): Database.Database {
  if (dbInstance) return dbInstance;
  const db = new Database(dbPath);
  db.pragma("journal_mode = WAL");
  db.pragma("foreign_keys = ON");
  db.exec(`
    CREATE TABLE IF NOT EXISTS comments (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      parent_id INTEGER REFERENCES comments(id) ON DELETE CASCADE,
      author TEXT NOT NULL,
      body TEXT NOT NULL,
      created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%fZ', 'now'))
    );
  `);
  db.exec(`CREATE INDEX IF NOT EXISTS idx_comments_parent ON comments(parent_id);`);

  const row = db
    .prepare("SELECT COUNT(*) as count FROM comments")
    .get() as { count: number };

  if (row.count === 0) {
    seed(db);
  }

  dbInstance = db;
  return db;
}

function seed(db: Database.Database) {
  const insert = db.prepare(
    "INSERT INTO comments (parent_id, author, body) VALUES (?, ?, ?)"
  );
  const tx = db.transaction(() => {
    const alice = insert.run(null, "alice", "Welcome to the thread")
      .lastInsertRowid as number;
    const bob = insert.run(alice, "bob", "Thanks alice!")
      .lastInsertRowid as number;
    insert.run(bob, "carol", "Agreed, great start");
    insert.run(null, "dave", "Separate top-level thought");
  });
  tx();
}

/**
 * Build the full comment tree in memory. Returns root-level nodes (parent_id = null)
 * with their descendants attached. Each node also receives a `totalReplies` count.
 */
export function getCommentTree(): CommentNode[] {
  const db = getDb();
  const rows = db
    .prepare(
      "SELECT id, parent_id, author, body, created_at FROM comments ORDER BY id ASC"
    )
    .all() as CommentRow[];

  const byId = new Map<number, CommentNode>();
  for (const r of rows) {
    byId.set(r.id, {
      id: r.id,
      parentId: r.parent_id,
      author: r.author,
      body: r.body,
      createdAt: r.created_at,
      children: [],
    });
  }

  const roots: CommentNode[] = [];
  for (const node of byId.values()) {
    if (node.parentId !== null && byId.has(node.parentId)) {
      byId.get(node.parentId)!.children.push(node);
    } else {
      roots.push(node);
    }
  }

  return roots;
}

export function insertComment(input: {
  parentId: number | null;
  author: string;
  body: string;
}): CommentRow {
  const db = getDb();
  const stmt = db.prepare(
    "INSERT INTO comments (parent_id, author, body) VALUES (?, ?, ?)"
  );
  const info = stmt.run(input.parentId, input.author, input.body);
  const id = info.lastInsertRowid as number;
  const row = db
    .prepare(
      "SELECT id, parent_id, author, body, created_at FROM comments WHERE id = ?"
    )
    .get(id) as CommentRow;
  return row;
}

export function getCommentDepths(): Map<number, number> {
  // Compute depth (0 for top-level, +1 per level) by walking the tree.
  const depths = new Map<number, number>();
  const roots = getCommentTree();
  const walk = (node: CommentNode, depth: number) => {
    depths.set(node.id, depth);
    for (const child of node.children) {
      walk(child, depth + 1);
    }
  };
  for (const r of roots) walk(r, 0);
  return depths;
}

export function getReplyCounts(): Map<number, number> {
  // For each comment id, count the number of descendants.
  const counts = new Map<number, number>();
  const roots = getCommentTree();
  const walk = (node: CommentNode): number => {
    let total = node.children.length;
    for (const child of node.children) {
      total += walk(child);
    }
    counts.set(node.id, total);
    return total;
  };
  for (const r of roots) walk(r);
  return counts;
}

import { component$, Slot } from "@builder.io/qwik";

export default component$(() => {
  return (
    <main>
      <Slot />
    </main>
