});

import { component$, useSignal, $ } from "@builder.io/qwik";
import { Form, type ActionStore } from "@builder.io/qwik-city";
import type { CommentNode } from "./lib/db";

export interface CommentProps {
  node: CommentNode;
  depth: number;
  replyCount: number;
  // Qwik serializes the action store lazily when used in client code; here we
  // accept the per-parent action store so each comment can submit to its own
  // reply action. The action must take fields `author`, `body`, `parentId`.
  replyAction: ActionStore<unknown, { author: string; body: string; parentId: number }, true>;
}

export const Comment = component$<CommentProps>(
  ({ node, depth, replyCount, replyAction }) => {
    const collapsed = useSignal(false);
    const hasChildren = node.children.length > 0;

    const toggle = $(() => {
      collapsed.value = !collapsed.value;
    });

    return (
      <div class="comment" data-comment-id={node.id} data-depth={depth}>
        <div class="comment-header">
          <span class="comment-author">{node.author}</span>
          <span class="comment-meta">{new Date(node.createdAt).toLocaleString()}</span>
        </div>
        <div class="comment-body">{node.body}</div>
        <div class="comment-meta">
          <span data-reply-count={replyCount}>
            {replyCount} {replyCount === 1 ? "reply" : "replies"}
          </span>
          {hasChildren && (
            <button
              type="button"
              class="toggle-btn"
              data-testid={`toggle-${node.id}`}
              onClick$={toggle}
              aria-expanded={!collapsed.value}
            >
              {collapsed.value ? "Expand" : "Collapse"}
            </button>
          )}
        </div>

        {!collapsed.value && hasChildren && (
          <div class="children">
            {node.children.map((child) => (
              <Comment
                key={child.id}
                node={child}
                depth={depth + 1}
                replyCount={countDescendants(child)}
                replyAction={replyAction}
              />
            ))}
          </div>
        )}

        {collapsed.value && hasChildren && (
          <div class="collapsed-hint">(subtree collapsed)</div>
        )}

        <Form action={replyAction} class="reply-form">
          <input type="hidden" name="parentId" value={node.id} />
          <input type="text" name="author" placeholder="Author" />
          <textarea
            name="body"
            placeholder="Write a reply..."
            rows={2}
          ></textarea>
          {replyAction.value?.failed && replyAction.value.fieldErrors && (
            <div class="error">
              {Object.values(replyAction.value.fieldErrors)
                .flat()
                .filter(Boolean)
                .join(" ")}
            </div>
          )}
          <button type="submit">Reply</button>
        </Form>
      </div>
    );
  }
);

function countDescendants(node: CommentNode): number {
  let total = node.children.length;
  for (const child of node.children) {
    total += countDescendants(child);
  }
  return total;
}

import { component$ } from "@builder.io/qwik";
import {
  routeLoader$,
  routeAction$,
  Form,
  zod$,
  z,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { Comment } from "../components/comment";
import {
  getCommentTree,
  getReplyCounts,
  insertComment,
  type CommentNode,
} from "../lib/db";

interface FlatComment {
  id: number;
  parentId: number | null;
  author: string;
  body: string;
  createdAt: string;
  depth: number;
  replyCount: number;
}

interface PageData {
  flat: FlatComment[];
}

export const useCommentsLoader = routeLoader$(async () => {
  const tree = getCommentTree();
  const counts = getReplyCounts();

  const flat: FlatComment[] = [];

  const walk = (node: CommentNode, depth: number) => {
    flat.push({
      id: node.id,
      parentId: node.parentId,
      author: node.author,
      body: node.body,
      createdAt: node.createdAt,
      depth,
      replyCount: counts.get(node.id) ?? 0,
    });
    for (const child of node.children) {
      walk(child, depth + 1);
    }
  };

  for (const root of tree) {
    walk(root, 0);
  }

  return { flat } satisfies PageData;
});

export const useReplyAction = routeAction$(
  async (data, { fail }) => {
    // Server-side validation in addition to zod$ validation.
    if (!data.author.trim() || !data.body.trim()) {
      return fail(400, {
        message: "Author and body are required",
        fieldErrors: {
          author: !data.author.trim() ? ["Author is required"] : [],
          body: !data.body.trim() ? ["Body is required"] : [],
        },
      });
    }
    insertComment({
      parentId: data.parentId ?? null,
      author: data.author.trim(),
      body: data.body.trim(),
    });
    return { success: true };
  },
  zod$({
    author: z.string().min(1, "Author is required").max(100),
    body: z.string().min(1, "Body is required").max(10000),
    parentId: z
      .union([z.string(), z.number()])
      .optional()
      .transform((v) => {
        if (v === undefined || v === null || v === "") return null;
        const n = typeof v === "string" ? Number(v) : v;
        if (!Number.isFinite(n)) return null;
        return n as number;
      }),
  })
);

export const useRootCommentAction = routeAction$(
  async (data, { fail }) => {
    if (!data.author.trim() || !data.body.trim()) {
      return fail(400, {
        message: "Author and body are required",
        fieldErrors: {
          author: !data.author.trim() ? ["Author is required"] : [],
          body: !data.body.trim() ? ["Body is required"] : [],
        },
      });
    }
    insertComment({
      parentId: null,
      author: data.author.trim(),
      body: data.body.trim(),
    });
    return { success: true };
  },
  zod$({
    author: z.string().min(1, "Author is required").max(100),
    body: z.string().min(1, "Body is required").max(10000),
  })
);

export default component$(() => {
  const data = useCommentsLoader();
  const replyAction = useReplyAction();
  const rootAction = useRootCommentAction();

  // Build the in-memory tree from flat data so we can render recursively.
  type Renderable = FlatComment & { children: Renderable[] };
  const byId = new Map<number, Renderable>();
  for (const c of data.value.flat) {
    byId.set(c.id, { ...c, children: [] });
  }
  const renderableRoots: Renderable[] = [];
  for (const c of data.value.flat) {
    const node = byId.get(c.id)!;
    if (c.parentId !== null && byId.has(c.parentId)) {
      byId.get(c.parentId)!.children.push(node);
    } else {
      renderableRoots.push(node);
    }
  }

  const renderTree = (nodes: Renderable[]): JSX.Element[] => {
    return nodes.map((n) => (
      <Comment
        key={n.id}
        node={{
          id: n.id,
          parentId: n.parentId,
          author: n.author,
          body: n.body,
          createdAt: n.createdAt,
          children: n.children.map((c) => ({
            id: c.id,
            parentId: c.parentId,
            author: c.author,
            body: c.body,
            createdAt: c.createdAt,
            children: [],
          })),
        }}
        depth={n.depth}
        replyCount={n.replyCount}
        replyAction={replyAction}
      />
    ));
  };

  return (
    <div>
      <h1>Nested Comments</h1>

      <Form action={rootAction} class="root-form">
        <h2>Add a new top-level comment</h2>
        <input type="text" name="author" placeholder="Author" />
        <textarea name="body" placeholder="Share your thoughts..." rows={3}></textarea>
        {rootAction.value?.failed && rootAction.value.fieldErrors && (
          <div class="error">
            {Object.values(rootAction.value.fieldErrors)
              .flat()
              .filter(Boolean)
              .join(" ")}
          </div>
        )}
        <button type="submit">Post comment</button>
      </Form>

      <h2>Thread</h2>
      {renderableRoots.length === 0 && <p>No comments yet.</p>}
      <div class="thread">{renderTree(renderableRoots)}</div>
    </div>
  );
});

export const head: DocumentHead = {
  title: "Qwik Nested Comments",
};

