    } else {
      roots.push(node);
    }
  }

  // Convert Renderable tree to CommentNode tree (preserves full children).
  const toCommentNode = (n: Renderable): CommentNode => ({
    id: n.id,
    parentId: n.parentId,
    author: n.author,
    body: n.body,
    createdAt: n.createdAt,
    children: n.children.map(toCommentNode),
