      <div class="thread">
        {roots.map((n) => (
          <Comment
            key={n.id}
            node={toCommentNode(n)}
            depth={n.depth}
            replyCount={n.replyCount}
            replyAction={replyAction}
          />
        ))}
      </div>
    </div>
  );
